// Validate + authorize BEFORE touching the HivePilot API.
// Inputs come from query (?run_id=&action=&token=) or JSON body.
const src = { ...( $json.query || {} ), ...( $json.body || {} ) };
const runId = String(src.run_id ?? '');
const action = String(src.action ?? '');
const token = String(src.token ?? '');
const secret = $env.HIVEPILOT_APPROVE_SECRET || '';

if (!secret || token !== secret) {
  throw new Error('unauthorized: bad or missing token');
}
if (!/^[0-9]+$/.test(runId)) {
  throw new Error('invalid run_id (must be digits)');
}
if (action !== 'approve' && action !== 'deny') {
  throw new Error("invalid action (must be 'approve' or 'deny')");
}
return [{ json: { run_id: runId, action } }];
